-- ----------------------------
-- Table structure for collection_runs
-- ----------------------------
DROP TABLE IF EXISTS `collection_runs`;
CREATE TABLE `collection_runs`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '采集批次ID',
  `platform_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台编码，如 ev_station_pluz',
  `run_label` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '批次标签，格式：{platform}_{YYYYMMDD_HHMM}_{mode}',
  `mode` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'full' COMMENT '采集模式：full=全量采集，refresh=刷新采集',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'running' COMMENT '批次状态：running=进行中，completed=已完成',
  `total_stations` int UNSIGNED NULL DEFAULT NULL COMMENT '目标站点总数',
  `collected_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '已成功采集并提交的站点数',
  `started_at` datetime NOT NULL COMMENT '批次开始时间',
  `completed_at` datetime NULL DEFAULT NULL COMMENT '批次完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_collection_runs_label`(`run_label` ASC) USING BTREE,
  INDEX `idx_collection_runs_platform_status_started`(`platform_code` ASC, `status` ASC, `started_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '采集批次表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of collection_runs
-- ----------------------------

-- ----------------------------
-- Table structure for connector_status_snapshots
-- ----------------------------
DROP TABLE IF EXISTS `connector_status_snapshots`;
CREATE TABLE `connector_status_snapshots`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '枪口状态快照ID',
  `run_id` bigint UNSIGNED NOT NULL COMMENT '采集批次ID，关联 collection_runs.id',
  `station_id` bigint UNSIGNED NOT NULL COMMENT '站点ID，关联 station_sites.id',
  `platform_unit_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台侧充电桩ID，如 Charger ID',
  `unit_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '充电桩名称，如 TS (133A Max Current)',
  `connector_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '枪口位置/名称，如 ซ้าย-A、ขวา-B',
  `connector_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '枪口类型，如 DC CCS COMBO 2、AC Type 2',
  `power_text` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '功率原始文本，如 Max 120 kW',
  `power_kw` decimal(8, 2) NULL DEFAULT NULL COMMENT '功率数值，单位 kW',
  `day_price_text` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `day_price_per_kwh` decimal(10, 4) NULL DEFAULT NULL,
  `night_price_text` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `night_price_per_kwh` decimal(10, 4) NULL DEFAULT NULL,
  `status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '枪口状态，如 Available、Occupied、Closed',
  `time_period` enum('day','night') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '采集时段：day=白天，night=夜间',
  `raw_data` json NULL COMMENT '枪口原始采集数据JSON，包含充电桩和枪口信息',
  `collected_at` datetime NOT NULL COMMENT '快照采集时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_css_run_station`(`run_id` ASC, `station_id` ASC) USING BTREE,
  INDEX `idx_css_station_collected`(`station_id` ASC, `collected_at` ASC) USING BTREE,
  INDEX `idx_css_unit_connector`(`platform_unit_id` ASC, `connector_name` ASC) USING BTREE,
  INDEX `idx_css_status_period`(`status` ASC, `time_period` ASC) USING BTREE,
  INDEX `idx_css_price_power`(`day_price_per_kwh` ASC, `power_kw` ASC) USING BTREE,
  CONSTRAINT `fk_css_run` FOREIGN KEY (`run_id`) REFERENCES `collection_runs` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_css_station` FOREIGN KEY (`station_id`) REFERENCES `station_sites` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3478 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '枪口状态快照表，包含充电桩信息' ROW_FORMAT = DYNAMIC;

