-- Records of connector_status_snapshots
-- ----------------------------

-- ----------------------------
-- Table structure for station_sites
-- ----------------------------
DROP TABLE IF EXISTS `station_sites`;
CREATE TABLE `station_sites`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '站点ID',
  `platform_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台编码，如 ev_station_pluz',
  `station_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '站点名称',
  `brief_address` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '简略地址，来自站点列表页',
  `address` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '完整地址，来自详情页 More information',
  `overall_status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '站点整体状态，如 Available、Closed',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '站点备注',
  `hours_text` json NULL COMMENT '营业时间JSON，按星期存储',
  `latitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '经度',
  `google_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Google Maps 分享链接',
  `collection_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '采集状态：pending=待采集，completed=已完成',
  `raw_data` json NULL COMMENT '站点原始采集数据JSON',
  `last_collected_at` datetime NULL DEFAULT NULL COMMENT '最近一次采集完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_station_platform_name`(`platform_code` ASC, `station_name` ASC) USING BTREE,
  INDEX `idx_station_platform_status`(`platform_code` ASC, `collection_status` ASC) USING BTREE,
  INDEX `idx_station_lat_lng`(`latitude` ASC, `longitude` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3169 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '充电站点表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of station_sites
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
